import React from "react";
import { Box, Button, Grid } from "@mui/material";

type CustomButtonProps = {
  title: string;
  width?: string;
  onClick?: () => void;
  type?: "button" | "submit";
};

const CustomButton = ({ title, onClick, width, type = "button" }: CustomButtonProps) => {
  const handleClick = () => {
    if (type === "button" && onClick) {
      onClick();
    }
  };

  return (
    <Box width={width || '100%'}>
      <Button
        type={type === "submit" ? "submit" : "button"}
        variant="contained"
        color="secondary"
        fullWidth
        sx={{ height: 48 }}
        onClick={handleClick}
      >
        {title}
      </Button>
    </Box>
  );
};

export default CustomButton;
